import{t as e}from"../common-tbeebdoN.js";var t=e(`.container`);t.append(`<div><h1>About</h1><div class="user-list"><div class="loading">加载中...</div></div></div>`),window.isSubProject&&fetch(`/api/user/all`).then(e=>e.json()).then(n=>{e(`.loading`).hide();let r=n.data||[];if(r.length>0){let n=e(`<ul></ul>`).append(r.map(e=>`<li>${e.name} - ${e.email}</li>`));t.find(`.user-list`).append(n)}else t.find(`.user-list`).append(`<div class="empty">暂无用户</div>`)});